SELECT count(*) FROM company_name, movie_companies, title, cast_info, company_type, kind_type, name, char_name WHERE movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND title.kind_id = kind_type.id AND cast_info.person_id = name.id AND cast_info.person_role_id = char_name.id;